import sys
import os

# Pleromatic Frame header is approx 64-128 bytes depending on attributes.
# We'll just look at the last 1024 bytes (the newest row).
path = "spectrum_waterfall.frame"
if not os.path.exists(path):
    print("Frame not found.")
    sys.exit(1)

with open(path, "rb") as f:
    data = f.read()
    
# Frame data is the bulk of the file.
payload = data[-1024:] 
vals = list(payload)
print(f"Frame Size: {len(data)} bytes")
print(f"Newest Row Stats: Min={min(vals)}, Max={max(vals)}, Avg={sum(vals)/len(vals):.2f}")
